message.content:
Ecco un modulo JavaScript ES2022 per un form dinamico con tutte le funzionalità richieste:

```html
<!-- Markup minimo necessario -->
<form id="dynamicForm">
  <div class="form-group">
    <label for="name">Nome:</label>
    <input type="text" id="name" name="name" required aria-required="true">
    <span class="error-message" role="alert" aria-live="polite"></span>
  </div>

  <div class="form-group">
    <label for="email">Email:</label>
    <input type="email" id="email" name="email" required aria-required="true">
    <span class="error-message" role="alert" aria-live="polite"></span>
  </div>

  <div class="form-group">
    <label for="message">Messaggio:</label>
    <textarea id="message" name="message" required aria-required="true"></textarea>
    <span class="error-message" role="alert" aria-live="polite"></span>
  </div>

  <button type="submit" id="submitBtn">Invia</button>
  <div id="status" role="status" aria-live="polite"></div>
</form>
```

```javascript
// dynamicForm.js - ES2022 Module
export class DynamicForm {
  #form;
  #submitBtn;
  #statusEl;
  #abortController = null;
  #isSubmitting = false;
  #retryCount = 0;
  #maxRetries = 3;

  constructor(formId = 'dynamicForm') {
    this.#form = document.getElementById(formId);
    if (!this.#form) throw new Error(`Form #${formId} not found`);

    this.#submitBtn = this.#form.querySelector('#submitBtn');
    this.#statusEl = this.#form.querySelector('#status');

    this.#setupValidation();
    this.#setupSubmit();
  }

  // Validazione accessibile
  #setupValidation() {
    const fields = this.#form.querySelectorAll('input, textarea');

    fields.forEach(field => {
      const errorSpan = field.closest('.form-group')?.querySelector('.error-message');

      // Validazione in tempo reale
      field.addEventListener('input', () => {
        this.#validateField(field, errorSpan);
      });

      field.addEventListener('blur', () => {
        this.#validateField(field, errorSpan);
      });

      // Validazione al submit
      field.addEventListener('invalid', (e) => {
        e.preventDefault();
        this.#validateField(field, errorSpan);
      });
    });
  }

  #validateField(field, errorSpan) {
    let error = '';

    if (field.required && !field.value.trim()) {
      error = 'Campo obbligatorio';
    } else if (field.type === 'email' && !this.#isValidEmail(field.value)) {
      error = 'Email non valida';
    } else if (field.tagName === 'TEXTAREA' && field.value.trim().length < 10) {
      error = 'Il messaggio deve contenere almeno 10 caratteri';
    }

    // Aggiornamento accessibile
    if (errorSpan) {
      errorSpan.textContent = error;
      field.setAttribute('aria-invalid', error ? 'true' : 'false');
      field.setAttribute('aria-describedby', error ? errorSpan.id || 'error-' + field.name : '');
    }

    return !error;
  }

  #isValidEmail(email) {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }

  // Submit con fetch abortibile e retry
  #setupSubmit() {
    this.#form.addEventListener('submit', async (e) => {
      e.preventDefault();

      if (this.#isSubmitting) return;

      // Validazione finale
      let isValid = true;
      const fields = this.#form.querySelectorAll('input, textarea');
      fields.forEach(field => {
        const errorSpan = field.closest('.form-group')?.querySelector('.error-message');
        if (!this.#validateField(field, errorSpan)) isValid = false;
      });

      if (!isValid) return;

      await this.#submitWithRetry();
    });
  }

  async #submitWithRetry() {
    this.#isSubmitting = true;
    this.#retryCount = 0;

    while (this.#retryCount <= this.#maxRetries) {
      this.#abortController = new AbortController();

      try {
        this.#setLoading(true);

        const formData = new FormData(this.#form);
        const response = await fetch('/api/submit', {
          method: 'POST',
          body: formData,
          signal: this.#abortController.signal
        });

        if (!response.ok) throw new Error(`HTTP ${response.status}`);

        const result = await response.json();
        this.#handleSuccess(result);
        return;

      } catch (error) {
        if (error.name === 'AbortError') {
          // Richiesta annullata dall'utente
          this.#setLoading(false);
          this.#isSubmitting = false;
          return;
        }

        this.#retryCount++;

        if (this.#retryCount > this.#maxRetries) {
          this.#handleError(error);
          return;
        }

        // Attesa prima del retry (backoff esponenziale)
        await new Promise(resolve => setTimeout(resolve, 1000 * this.#retryCount));
      }
    }
  }

  // Metodo pubblico per annullare la richiesta
  abort() {
    if (this.#abortController) {
      this.#abortController.abort();
      this.#abortController = null;
    }
  }

  // Gestione stato loading
  #setLoading(isLoading) {
    this.#submitBtn.disabled = isLoading;
    this.#submitBtn.textContent = isLoading ? 'Invio in corso...' : 'Invia';
    this.#statusEl.textContent = isLoading ? 'Invio in corso...' : '';
    this.#statusEl.setAttribute('aria-busy', isLoading ? 'true' : 'false');
  }

  // Rendering sicuro degli errori (previene XSS)
  #handleError(error) {
    this.#isSubmitting = false;
    this.#setLoading(false);

    // Sanitizzazione del messaggio di errore
    const safeMessage = this.#sanitize(error.message || 'Errore durante l\'invio');
    this.#statusEl.textContent = `❌ ${safeMessage}`;
    this.#statusEl.className = 'error';

    // Annuncio per screen reader
    this.#statusEl.focus();
  }

  #handleSuccess(result) {
    this.#isSubmitting = false;
    this.#setLoading(false);

    const safeMessage = this.#sanitize(result.message || 'Invio completato con successo');
    this.#statusEl.textContent = `✅ ${safeMessage}`;
    this.#statusEl.className = 'success';

    // Reset form
    this.#form.reset();

    // Reset errori
    this.#form.querySelectorAll('.error-message').forEach(el => el.textContent = '');
    this.#form.querySelectorAll('[aria-invalid]').forEach(el => el.removeAttribute('aria-invalid'));

    this.#statusEl.focus();
  }

  #sanitize(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

// Esportazione default per uso immediato
export default DynamicForm;
```

**Caratteristiche principali:**

- ✅ **Validazione accessibile**: attributi ARIA (`aria-invalid`, `aria-describedby`, `aria-required`), messaggi di errore con `role="alert"` e `aria-live="polite"`
- ✅ **Submit con fetch abortibile**: utilizza `AbortController` per annullare richieste in corso
- ✅ **Retry automatico**: fino a 3 tentativi con backoff esponenziale
- ✅ **Stato loading**: disabilita il pulsante e mostra feedback visivo
- ✅ **Rendering sicuro**: sanitizzazione del testo con `textContent` per prevenire XSS
- ✅ **Supporto screen reader**: focus sugli elementi di stato e messaggi live

**Utilizzo:**
```javascript
import DynamicForm from './dynamicForm.js';

const form = new DynamicForm();
// Per annullare una richiesta in corso:
// form.abort();
```
